// RecordRequest records metrics for a completed request
func (m *CustomMetrics) RecordRequest(userID, method, endpoint, statusCode, userAgent, region string, duration time.Duration, respSize float64) {
	m.requestsTotal.With(prometheus.Labels{
		"user_id":    userID,
		"method":     method,
		"endpoint":   endpoint,
		"status_code": statusCode,
		"user_agent": userAgent,
		"region":     region,
	}).Inc()

	m.requestDuration.With(prometheus.Labels{
		"user_id":    userID,
		"method":     method,
		"endpoint":   endpoint,
		"status_code": statusCode,
		"region":     region,
	}).Observe(duration.Seconds())

	m.responseSize.With(prometheus.Labels{
		"user_id":  userID,
		"endpoint": endpoint,
		"method":   method,
	}).Observe(respSize)
}

// RecordError records an error metric
func (m *CustomMetrics) RecordError(userID, endpoint, errorType, statusCode string) {
	m.errorsTotal.With(prometheus.Labels{
		"user_id":    userID,
		"endpoint":   endpoint,
		"error_type": errorType,
		"status_code": statusCode,
	}).Inc()
}

// TrackInFlight increments/decrements in-flight request gauge
func (m *CustomMetrics) TrackInFlight(userID, endpoint string, delta float64) {
	m.requestsInFlight.With(prometheus.Labels{
		"user_id":  userID,
		"endpoint": endpoint,
	}).Add(delta)
}

// SetUserActive marks a user as active
func (m *CustomMetrics) SetUserActive(userID, region, subscriptionTier string) {
	m.userActiveGauge.With(prometheus.Labels{
		"user_id":           userID,
		"region":            region,
		"subscription_tier": subscriptionTier,
	}).Set(1)
}

// metricsMiddleware wraps an HTTP handler to automatically record metrics
func metricsMiddleware(metrics *CustomMetrics, next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		userID := r.Header.Get("X-User-ID")
		if userID == "" {
			userID = r.URL.Query().Get("user_id")
		}
		if userID == "" {
			userID = "anonymous"
		}

		region := r.Header.Get("X-Region")
		if region == "" {
			region = r.URL.Query().Get("region")
		}
		if region == "" {
			region = "unknown"
		}

		userAgent := r.UserAgent()
		if userAgent == "" {
			userAgent = "unknown"
		}

		endpoint := r.URL.Path
		method := r.Method

		// Track in-flight
		metrics.TrackInFlight(userID, endpoint, 1)
		defer metrics.TrackInFlight(userID, endpoint, -1)

		// Wrap response writer to capture status code and size
		wrappedWriter := &responseWriterWrapper{
			ResponseWriter: w,
			statusCode:     http.StatusOK,
		}

		start := time.Now()
		next(wrappedWriter, r)
		duration := time.Since(start)

		statusCode := fmt.Sprintf("%d", wrappedWriter.statusCode)

		metrics.RecordRequest(userID, method, endpoint, statusCode, userAgent, region, duration, float64(wrappedWriter.bytesWritten))

		if wrappedWriter.statusCode >= 400 {
			errorType := "client_error"
			if wrappedWriter.statusCode >= 500 {
				errorType = "server_error"
			}
			metrics.RecordError(userID, endpoint, errorType, statusCode)
		}
	}
}

// responseWriterWrapper captures response metadata
type responseWriterWrapper struct {
	http.ResponseWriter
	statusCode   int
	bytesWritten int
}

func (w *responseWriterWrapper) WriteHeader(code int) {
	w.statusCode = code
	w.ResponseWriter.WriteHeader(code)
}

func (w *responseWriterWrapper) Write(b []byte) (int, error) {
	n, err := w.ResponseWriter.Write(b)
	w.bytesWritten += n
	return n, err
}

